import{_ as n,o as a,c as p,e}from"./app-2dc9ef31.js";const o={},s=e(`<h2 id="monorepo是啥" tabindex="-1"><a class="header-anchor" href="#monorepo是啥" aria-hidden="true">#</a> monorepo是啥</h2><p>Monorepo的意思是在版本控制系统的单个代码库里包含了许多项目的代码。这些项目虽然有可能是相关的，但通常在逻辑上是独立的，并由不同的团队维护。 在前端使用角度来看，monorepo 就是把多个工程放到一个 git 仓库中进行管理，因此他们可以共享同一套构建流程、代码规范也可以做到统一，特别是如果存在模块间的相互引用的情况，查看代码、修改bug、调试等会更加方便。</p><h2 id="pnpm-workspace" tabindex="-1"><a class="header-anchor" href="#pnpm-workspace" aria-hidden="true">#</a> pnpm + workspace</h2><h3 id="创建项目" tabindex="-1"><a class="header-anchor" href="#创建项目" aria-hidden="true">#</a> 创建项目</h3><ol><li>建一个项目目录，创建好目录执行pnpm init,会在根目录生成一个packaeg.json文件。</li><li>创建 pnpm-workspace.yaml和.npmrc文件</li></ol><ul><li>pnpm-workspace.yaml <ul><li>定义了 工作空间 的根目录，并能够使您从工作空间中包含 / 排除目录 。 默认情况下，包含所有子目录。即使使用了自定义目录位置通配符，根目录下的package目录也总是被包含。</li></ul></li><li>.npmrc <ul><li>pnpm 从命令行、环境变量和 .npmrc 文件中获取其配置。</li><li>pnpm config 命令可用于更新和编辑 用户和全局 .npmrc 文件的内容。 在这里，我们在.npmrc文件配置了，engine-strict=true 结合根目录的package.json中的 engines 字段，可以指定运行的 node 版和 pnpm 版</li></ul></li></ul><ol start="3"><li>创建packages文件夹，进入目录创建我们子项目</li></ol><ul><li>lowcode-platform 采用umi创建,感兴趣的可以自行去umi官网查看</li><li>ui-material 采用阿里的低代码物料脚手架创建，感兴趣的可以去看lowcode-engine</li></ul><ol start="4"><li>我们假设把ui-material项目作为基础库，让lowcode-platform去直接引用ui-material库，我们可以在根目录执行 pnpm add ui-material -r --filter lowcode-platform。 执行完成之后，我们就可以在lowcode-platform项目下直接引用改模块，不需要安装。这里我们用到了三个命令，分别是add,-r,--filter。具体详细内容可以参考官网。</li></ol><ul><li>add 命令可以参考：pnpm add</li><li>-r 参数可以参考：pnpm -r, --recursive</li><li>--filter 参数可以参考：过滤</li></ul><ol start="5"><li>接下来，我们可以在根目录下执行下pnpm i安装下依赖，配置下启动脚本</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>  <span class="token string-property property">&quot;clean-install&quot;</span><span class="token operator">:</span> <span class="token string">&quot;pnpm clean &amp;&amp; rm -rf ./{packages}/*/node_modules node_modules &amp;&amp; pnpm i&quot;</span><span class="token punctuation">,</span>
  <span class="token string-property property">&quot;dev&quot;</span><span class="token operator">:</span> <span class="token string">&quot;pnpm -F \\&quot;lowcode-platform\\&quot; dev&quot;</span><span class="token punctuation">,</span>
  <span class="token string-property property">&quot;build&quot;</span><span class="token operator">:</span> <span class="token string">&quot;pnpm -F \\&quot;lowcode-platform\\&quot; build&quot;</span><span class="token punctuation">,</span>
  <span class="token string-property property">&quot;dev:ui&quot;</span><span class="token operator">:</span> <span class="token string">&quot;pnpm -F \\&quot;ui-material\\&quot; lowcode:dev&quot;</span><span class="token punctuation">,</span>
  <span class="token string-property property">&quot;build:ui&quot;</span><span class="token operator">:</span> <span class="token string">&quot;pnpm -F \\&quot;ui-material\\&quot; lowcode:build&quot;</span><span class="token punctuation">,</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>到这里就可以了，你可以配置自己比较方便快捷的命令。</p><p>——————————分割线——————————</p><h2 id="pnpm的优势" tabindex="-1"><a class="header-anchor" href="#pnpm的优势" aria-hidden="true">#</a> pnpm的优势</h2><ul><li>快速安装： 由于pnpm使用了链接的方式来管理包，因此无需重新复制每个包文件，使得一次安装所需的时间大大减少。</li><li>节省磁盘空间： 由于同一个包只被保存在磁盘上一次，因此pnpm适用于多个项目使用同一依赖的情况。通过使用本地缓存，多个项目可以共享依赖包，极大地减少了磁盘空间的使用。</li><li>支持多语言开发： pnpm不仅支持Node.js，还包括许多其他的编程语言，例如TypeScript、Reason等。这使得使用pnpm的我们可以更容易地在一个项目中使用多种语言进行开发。</li><li>易于使用： pnpm基本命令与npm相同，所以只需要在使用上进行简单的修改即可。PNPM具有完善的文档和有效的社区支持。</li></ul>`,16),l=[s];function t(i,r){return a(),p("div",null,l)}const u=n(o,[["render",t],["__file","pnpmdeworkspaceshixianmonorepogongcheng.html.vue"]]);export{u as default};
